import { useContext } from 'react';
import { ComplaintContext } from '../context/ComplaintContext';

/**
 * useComplaint Hook
 * Custom hook to use ComplaintContext
 * Validates that it's being used within ComplaintProvider
 */
export const useComplaint = () => {
  const context = useContext(ComplaintContext);

  if (!context) {
    throw new Error(
      'useComplaint must be used within a ComplaintProvider. ' +
      'Make sure ComplaintProvider wraps your component.'
    );
  }

  return context;
};

export default useComplaint;
